import{_ as n,o,c as r,b as e,w as i,d as s,e as p,a as c,r as t}from"./app.dec15874.js";const d="/vite-press-blog/assets/chrome1.e610e76e.webp",m="/vite-press-blog/assets/chrome2.e1fd03be.webp",h="/vite-press-blog/assets/chrome3.8a85e8b0.webp",b="/vite-press-blog/assets/chrome4.74a5264c.webp",g="/vite-press-blog/assets/chrome5.7b987fb5.webp",_="/vite-press-blog/assets/chrome6.bf9d977c.webp",D="/vite-press-blog/assets/chrome7.3cdbbfd8.webp",u="/vite-press-blog/assets/chrome8.4b3679e3.webp",v="/vite-press-blog/assets/chrome9.05621a7a.webp",y="/vite-press-blog/assets/chrome10.f4161d54.webp",C="/vite-press-blog/assets/chrome11.83b05f70.webp",f="/vite-press-blog/assets/chrome12.a8bd292a.webp",V=JSON.parse('{"title":"DevTools Tips","description":"","frontmatter":{"createTime":"2022/10/25","tag":"chrome"},"headers":[{"level":2,"title":"Elements","slug":"elements","link":"#elements","children":[{"level":3,"title":"Element 状态","slug":"element-状态","link":"#element-状态","children":[]},{"level":3,"title":"快速定位 Element","slug":"快速定位-element","link":"#快速定位-element","children":[]},{"level":3,"title":"DOM 断点","slug":"dom-断点","link":"#dom-断点","children":[]},{"level":3,"title":"查看事件","slug":"查看事件","link":"#查看事件","children":[]},{"level":3,"title":"找到之前查看过的 DOM 元素","slug":"找到之前查看过的-dom-元素","link":"#找到之前查看过的-dom-元素","children":[]}]},{"level":2,"title":"Debugging","slug":"debugging","link":"#debugging","children":[]}],"relativePath":"basic-quality/browser/chrome-dev/skills/DevTools-tips/index.md","lastUpdated":1667281923000}'),x={name:"basic-quality/browser/chrome-dev/skills/DevTools-tips/index.md"},A=s("h1",{id:"devtools-tips",tabindex:"-1"},[p("DevTools Tips "),s("a",{class:"header-anchor",href:"#devtools-tips","aria-hidden":"true"},"#")],-1),T=c('<h2 id="elements" tabindex="-1">Elements <a class="header-anchor" href="#elements" aria-hidden="true">#</a></h2><p>这个功能肯定是大家经常用到的，我们可以通过它来可视化所有的 DOM 标签，可以查看任何 DOM 的属性，接下来我们就来学习一下关于这方面的 Tips。 <img src="'+d+'" alt="图片"></p><h3 id="element-状态" tabindex="-1">Element 状态 <a class="header-anchor" href="#element-状态" aria-hidden="true">#</a></h3><p>你可能会在开发中遇到这么一个场景：给一个 a 标签设置了多种状态下的样式，但是如果手动去改变状态的话就有点麻烦，这时候这个 Tips 就能帮你解决这个问题。 <img src="'+m+'" alt="图片"></p><p>可以从上图中看到，无论你想看到元素的何种状态下的样式，都只需要勾选相对应的状态就可以了，这是不是比手动更改方便多了？</p><h3 id="快速定位-element" tabindex="-1">快速定位 Element <a class="header-anchor" href="#快速定位-element" aria-hidden="true">#</a></h3><p>通常页面都是可以滚动的，那么如果想查看的元素不在当前窗口的话，你还需要滚动页面才能找到元素，这时候这个 Tips 就能帮你解决这个问题。 <img src="'+h+'" alt="图片"></p><p>当点击这个选项的时候，页面就会自动滚动到元素所在的位置，这样比边滚动边查看是否找到元素的方式方便多了。</p><h3 id="dom-断点" tabindex="-1">DOM 断点 <a class="header-anchor" href="#dom-断点" aria-hidden="true">#</a></h3><p>给 JS 打断点想必各位都听过，但是 DOM 断点知道的人应该就少了。如果你想查看一个 DOM 元素是如何通过 JS 更改的，你就可以使用这个功能。 <img src="'+b+'" alt="图片"></p><p>当我们给 ul 添加该断点以后，一旦 ul 子元素发生了改动，比如说增加了子元素的个数，那么就会自动跳转到对应的 JS 代码 <img src="'+g+'" alt="图片"></p><p>其实不光可以给 DOM 打断点，我们还可以给 Ajax 或者 Event Listener 打断点。 <img src="'+_+'" alt="图片"></p><h3 id="查看事件" tabindex="-1">查看事件 <a class="header-anchor" href="#查看事件" aria-hidden="true">#</a></h3><p>我们还可以通过 DevTools 来查看页面中添加了多少的事件。假如当你发现页面滚动起来有性能上的问题时，就可以查看一下有多少 scroll 事件被添加了 <img src="'+D+'" alt="图片"></p><h3 id="找到之前查看过的-dom-元素" tabindex="-1">找到之前查看过的 DOM 元素 <a class="header-anchor" href="#找到之前查看过的-dom-元素" aria-hidden="true">#</a></h3><p>不知道你是否遇到过这样的问题，找不到之前查看过的 DOM 元素在哪里了，需要一个个去找这就有点麻烦了，这时候你就可以使用这个功能。 <img src="'+u+'" alt="图片"></p><p>我们可以通过 $0 来找到上一次查看过的 DOM 元素，$1 就是上上次的元素，之后以此类推。这时候你可能会说，打印出来元素有啥用，在具体什么位置还要去找啊，不用急，马上我就可以解决这个问题 <img src="'+v+`" alt="图片"></p><p>当你点击这个选项时，页面立马会跳转至元素所在位置，并且 DevTools 也会变到 Elements 标签。</p><h2 id="debugging" tabindex="-1">Debugging <a class="header-anchor" href="#debugging" aria-hidden="true">#</a></h2><p>给 JS 打断点想必大家都会，但是打断点也是有一个不为人知的 Tips 的。</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">for</span><span style="color:#A6ACCD;"> (</span><span style="color:#C792EA;">let</span><span style="color:#A6ACCD;"> index </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> index </span><span style="color:#89DDFF;">&lt;</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">10</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> index</span><span style="color:#89DDFF;">++</span><span style="color:#A6ACCD;">) </span><span style="color:#89DDFF;">{</span><span style="color:#F07178;">   </span><span style="color:#676E95;font-style:italic;">// 各种逻辑   console.log(index) }</span></span>
<span class="line"></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>对于这段代码来说，如果我只想看到 index 为 5 时相应的断点信息，但是一旦打了断点，就会每次循环都会停下来，很浪费时间，那么通过这个小技巧我们就可以圆满解决这个问题 <img src="`+y+'" alt="图片"></p><p>首先我们先右键断点，然后选择 Edit breakpoint... 选项 <img src="'+C+'" alt="图片"></p><p>在弹框内输入 index === 5，这样断点就会变为橙色，并且只有当符合表达式的情况时断点才会被执行 <img src="'+f+'" alt="图片"></p>',24);function w(F,O,k,E,M,S){const a=t("ArticleMetadata"),l=t("ClientOnly");return o(),r("div",null,[A,e(l,null,{default:i(()=>[e(a)]),_:1}),T])}const $=n(x,[["render",w]]);export{V as __pageData,$ as default};
